import React from 'react';
import {
    ResponsiveContainer,
    AreaChart,
    Area,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
} from 'recharts';

/* ── Custom tooltip ──────────────────────────────────────────── */
function CustomTooltip({ active, payload, label }) {
    if (!active || !payload?.length) return null;
    return (
        <div className="glass-card px-3 py-2.5 shadow-card text-xs">
            <p className="text-white/50 mb-1.5 font-medium">{label}</p>
            {payload.map(p => (
                <div key={p.dataKey} className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full flex-shrink-0" style={{ background: p.color }} />
                    <span className="text-white/70 capitalize">{p.name}:</span>
                    <span className="text-white font-semibold">{p.value}</span>
                </div>
            ))}
        </div>
    );
}

/* ── Demo data ───────────────────────────────────────────────── */
const DEMO_DATA = [
    { day: 'Mon', overall: 55, fluency: 48, grammar: 60 },
    { day: 'Tue', overall: 62, fluency: 58, grammar: 65 },
    { day: 'Wed', overall: 58, fluency: 54, grammar: 62 },
    { day: 'Thu', overall: 71, fluency: 68, grammar: 74 },
    { day: 'Fri', overall: 75, fluency: 72, grammar: 78 },
    { day: 'Sat', overall: 80, fluency: 79, grammar: 82 },
    { day: 'Sun', overall: 84, fluency: 83, grammar: 86 },
];

/**
 * ProgressChart
 * Props:
 *   data    – array of { day, overall, fluency, grammar }  (optional, uses demo data if omitted)
 *   title   – string
 *   loading – boolean
 */
export default function ProgressChart({ data, title = 'Weekly Progress', loading = false }) {
    const chartData = data?.length ? data : DEMO_DATA;

    if (loading) {
        return (
            <div className="glass-card p-5 animate-pulse">
                <div className="h-4 w-36 bg-white/5 rounded mb-4" />
                <div className="h-48 bg-white/5 rounded-xl" />
            </div>
        );
    }

    return (
        <div className="glass-card p-5">
            {/* header */}
            <div className="flex items-center justify-between mb-4">
                <div>
                    <h3 className="section-title text-base">{title}</h3>
                    <p className="section-subtitle text-xs">Last 7 days · Score out of 100</p>
                </div>
                <div className="flex items-center gap-2">
                    {[
                        { label: 'Overall', color: '#4f8cff' },
                        { label: 'Fluency', color: '#a259ff' },
                        { label: 'Grammar', color: '#00e5a0' },
                    ].map(l => (
                        <div key={l.label} className="hidden sm:flex items-center gap-1">
                            <span className="w-2 h-2 rounded-full" style={{ background: l.color }} />
                            <span className="text-white/40 text-[10px]">{l.label}</span>
                        </div>
                    ))}
                </div>
            </div>

            <ResponsiveContainer width="100%" height={220}>
                <AreaChart data={chartData} margin={{ top: 4, right: 4, bottom: 0, left: -20 }}>
                    <defs>
                        <linearGradient id="colorOverall" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#4f8cff" stopOpacity={0.3} />
                            <stop offset="95%" stopColor="#4f8cff" stopOpacity={0} />
                        </linearGradient>
                        <linearGradient id="colorFluency" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#a259ff" stopOpacity={0.3} />
                            <stop offset="95%" stopColor="#a259ff" stopOpacity={0} />
                        </linearGradient>
                        <linearGradient id="colorGrammar" x1="0" y1="0" x2="0" y2="1">
                            <stop offset="5%" stopColor="#00e5a0" stopOpacity={0.3} />
                            <stop offset="95%" stopColor="#00e5a0" stopOpacity={0} />
                        </linearGradient>
                    </defs>

                    <CartesianGrid
                        strokeDasharray="3 3"
                        stroke="rgba(255,255,255,0.04)"
                        vertical={false}
                    />

                    <XAxis
                        dataKey="day"
                        tick={{ fill: 'rgba(255,255,255,0.3)', fontSize: 11 }}
                        axisLine={false} tickLine={false}
                    />
                    <YAxis
                        domain={[0, 100]}
                        tick={{ fill: 'rgba(255,255,255,0.3)', fontSize: 11 }}
                        axisLine={false} tickLine={false}
                    />

                    <Tooltip content={<CustomTooltip />} cursor={{ stroke: 'rgba(255,255,255,0.1)', strokeWidth: 1 }} />

                    <Area
                        type="monotone" dataKey="overall" name="Overall"
                        stroke="#4f8cff" strokeWidth={2}
                        fill="url(#colorOverall)"
                        dot={{ fill: '#4f8cff', r: 3, strokeWidth: 0 }}
                        activeDot={{ r: 5, fill: '#4f8cff' }}
                    />
                    <Area
                        type="monotone" dataKey="fluency" name="Fluency"
                        stroke="#a259ff" strokeWidth={2}
                        fill="url(#colorFluency)"
                        dot={{ fill: '#a259ff', r: 3, strokeWidth: 0 }}
                        activeDot={{ r: 5 }}
                    />
                    <Area
                        type="monotone" dataKey="grammar" name="Grammar"
                        stroke="#00e5a0" strokeWidth={2}
                        fill="url(#colorGrammar)"
                        dot={{ fill: '#00e5a0', r: 3, strokeWidth: 0 }}
                        activeDot={{ r: 5 }}
                    />
                </AreaChart>
            </ResponsiveContainer>
        </div>
    );
}
